var findSafeWalk = function(grid, health) {
    const m = grid.length, n = grid[0].length;
    const INF = Infinity;
    const dist = Array.from({ length: m }, () => new Array(n).fill(INF));
    dist[0][0] = grid[0][0];
    let dq = [[0, 0]];
    while (dq.length > 0) {
        const [r, c] = dq.shift();
        const d = dist[r][c];
        const deltas = [[1, 0], [-1, 0], [0, 1], [0, -1]];
        for (const [dr, dc] of deltas) {
            const nr = r + dr, nc = c + dc;
            if (nr >= 0 && nr < m && nc >= 0 && nc < n) {
                const nd = d + grid[nr][nc];
                if (nd < dist[nr][nc]) {
                    dist[nr][nc] = nd;
                    if (grid[nr][nc] === 0) {
                        dq.unshift([nr, nc]);
                    } else {
                        dq.push([nr, nc]);
                    }
                }
            }
        }
    }
    return dist[m - 1][n - 1] <= health - 1;
};
